@startuml
!theme plain

class "Scheduler" {
  [C] Scheduler
  o isMaster
}

class "Schedule" {
  [C] Schedule
}

class "ScheduleRecord" {
  [C] ScheduleRecord
  o timeout
}

class "Task" {
  [C] Task
  o lastStartTime
  o lastCompleteTime
}

"Scheduler" --> "Schedule" : 
"Schedule" --> "ScheduleRecord" : *
"ScheduleRecord" --> "Task" : list
"Scheduler" --> "Task" : run
"Scheduler" --> "Task" : watchdog

@enduml
